// Parametric control knob / dial
// ---------------------------------
// A generic, ergonomic control knob for potentiometers, encoders, valves, etc.
// Declares its tweakable dimensions via api.params so it drops straight into the
// Customizer panel. Defaults are tuned to be an attractive catalog entry.

const { Manifold, CrossSection } = api;

const p = api.params({
  diameter:    { type: 'number',  default: 34, min: 12, max: 80, step: 1, unit: 'mm',
                 label: 'Body diameter', help: 'Outer diameter at the grip.' },
  height:      { type: 'number',  default: 20, min: 6,  max: 50, step: 1, unit: 'mm',
                 label: 'Body height' },
  taper:       { type: 'number',  default: 0.78, min: 0.5, max: 1, step: 0.01,
                 label: 'Top taper', help: 'Top diameter as a fraction of the bottom — <1 flares the skirt outward for grip.' },
  gripCount:   { type: 'int',     default: 24, min: 0,  max: 60,
                 label: 'Grip count', help: 'Number of knurls/flutes. 0 = smooth.' },
  gripStyle:   { type: 'select',  default: 'knurled',
                 options: ['knurled', 'fluted', 'smooth'],
                 label: 'Grip style' },
  gripDepth:   { type: 'number',  default: 1.1, min: 0.2, max: 3, step: 0.1, unit: 'mm',
                 label: 'Grip depth' },
  bore:        { type: 'boolean', default: true,  label: 'Center shaft bore' },
  boreDiameter:{ type: 'number',  default: 6,  min: 2,  max: 20, step: 0.5, unit: 'mm',
                 label: 'Bore diameter', help: 'Only used when Center shaft bore is on.' },
  pointer:     { type: 'boolean', default: true,  label: 'Indicator pointer' },
});

const rBottom = p.diameter / 2;
const rTop = rBottom * p.taper;
const h = p.height;

// ---- Body: a revolved profile gives a softly domed top + a small chamfer at
//      the base so it reads as a real molded knob rather than a raw cylinder.
const domeRise = Math.min(h * 0.18, rTop * 0.5);     // gentle crown on top
const baseChamfer = Math.min(2, rBottom * 0.15, h * 0.2);

// Profile in (radial X, height Y). Walk the silhouette CCW.
const profile = CrossSection.ofPolygons([[
  [0, 0],                               // bottom centre
  [rBottom - baseChamfer, 0],           // bottom edge (start chamfer)
  [rBottom, baseChamfer],               // chamfer up to full radius
  [rTop, h - domeRise],                 // taper up the skirt
  [rTop * 0.72, h],                     // round the top shoulder in
  [0, h + domeRise * 0.35],             // domed centre top
]]);

let knob = Manifold.revolve(profile);

// ---- Indicator pointer ------------------------------------------------------
// A rounded nub riding the domed top so you can read the dial position. Added
// BEFORE grips/bore so a skirt notch can't sever it and the bore tunnels
// through it cleanly. It runs from the crown centre out past the rim, so it
// always shares plenty of volume with the body (no floating-island risk).
const topZ = h + domeRise * 0.35;                  // crown height
if (p.pointer) {
  const nub = Manifold.cylinder(rTop + 2, 1.7, 1.1)  // long enough to reach the rim
    .rotate([0, 90, 0])                            // lay it radial (+X)
    .translate([0, 0, topZ - 1.0]);                // start at centre, sit on the crown
  knob = api.expectUnion([knob, nub], { expectComponents: 1 });
}

// ---- Grips around the skirt -------------------------------------------------
// knurled = subtractive vertical notches; fluted = scalloped round channels.
// Guard the count: circularPattern requires >=1, and 'smooth' means none.
const wantGrips = p.gripStyle !== 'smooth' && p.gripCount >= 1;
if (wantGrips) {
  const ringR = rBottom;                          // notch centres sit on the rim
  // Confine cutters to a side "grip band": above the base chamfer, below the
  // top shoulder. This guarantees a notch grooves only the wall — it can never
  // sever the crown even at gripCount=1 (a single deep cut).
  const bandLo = baseChamfer + 0.5;
  const bandHi = (h - domeRise) - 0.5;
  const bandH = Math.max(1, bandHi - bandLo);
  const bandMid = (bandLo + bandHi) / 2;
  let cutter;
  if (p.gripStyle === 'knurled') {
    // A slim diamond prism that bites a V-ish notch into the rim.
    const w = Math.max(0.6, (2 * Math.PI * ringR) / p.gripCount * 0.55);
    cutter = Manifold.cube([p.gripDepth * 2, w, bandH], true)
      .rotate([0, 0, 45])                          // diamond profile -> knurl feel
      .translate([ringR, 0, bandMid]);
  } else {
    // fluted: round channels scooped out of the side.
    const fluteR = Math.max(0.8, (2 * Math.PI * ringR) / p.gripCount * 0.42);
    cutter = Manifold.cylinder(bandH, fluteR, fluteR)
      .translate([ringR + fluteR - p.gripDepth, 0, bandLo]);
  }
  // The notches only bite the skirt; the pointer rides above on the crown, so
  // a notch at the pointer's angle can't sever it.
  const grips = api.circularPattern(cutter, p.gripCount, { axis: 'z' });
  knob = knob.subtract(grips);
}

// ---- Center shaft bore ------------------------------------------------------
// Subtracted last so it cleanly tunnels through any pointer/grip features.
// A real shaft bore makes the solid genus-1 (one through hole). Clamp the
// radius so a too-wide bore can never eat the whole body: always keep >=1mm of
// wall inside the narrower (top) radius.
if (p.bore) {
  const maxBoreR = Math.max(0.5, rTop - 1.0);
  const br = Math.min(p.boreDiameter / 2, maxBoreR);
  const boreH = topZ + 2;                          // through the crown
  const bore = Manifold.cylinder(boreH + 1, br, br).translate([0, 0, -1]);
  knob = knob.subtract(bore);
}

return knob;
